import{_ as o,C as n,o as s,c as l,E as i,w as r,a,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Moving to Cyprus","description":"Immigration pathways and relocation guide for Cyprus","frontmatter":{"layout":"doc","title":"Moving to Cyprus","description":"Immigration pathways and relocation guide for Cyprus"},"headers":[],"relativePath":"europe/cyprus/moving-there.md","filePath":"europe/cyprus/moving-there.md","lastUpdated":null}'),h={name:"europe/cyprus/moving-there.md"};function c(g,t,u,m,p,f){const e=n("Badge");return s(),l("div",null,[i(e,{variant:"green"},{default:r(()=>[...t[0]||(t[0]=[a("EU Free Movement",-1)])]),_:1}),i(e,{variant:"green"},{default:r(()=>[...t[1]||(t[1]=[a("Digital Nomad Visa",-1)])]),_:1}),t[2]||(t[2]=d('<h1 id="moving-to-cyprus" tabindex="-1">Moving to Cyprus <a class="header-anchor" href="#moving-to-cyprus" aria-label="Permalink to &quot;Moving to Cyprus&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eu-eea-swiss-citizens" tabindex="-1">EU/EEA/Swiss Citizens <a class="header-anchor" href="#eu-eea-swiss-citizens" aria-label="Permalink to &quot;EU/EEA/Swiss Citizens&quot;">​</a></h3><p>Cyprus grants full <strong>free movement rights</strong> to EU/EEA/Swiss citizens:</p><ul><li><strong>Up to 4 months</strong>: No registration required</li><li><strong>Over 4 months</strong>: Must register with the Civil Registry and Migration Department for a <strong>Yellow Slip</strong> (registration certificate)</li><li><strong>Requirements</strong>: Valid passport or ID, proof of employment, sufficient funds, or health insurance</li><li><strong>Right to work</strong>: Automatic</li><li><strong>After 5 years</strong>: Eligible for permanent residence</li></ul><h3 id="non-eu-citizens" tabindex="-1">Non-EU Citizens <a class="header-anchor" href="#non-eu-citizens" aria-label="Permalink to &quot;Non-EU Citizens&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Description</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Visa</td><td>Employment with Cypriot employer</td><td>Job offer, employer sponsorship</td><td>2 years, renewable</td></tr><tr><td>Student Visa</td><td>Full-time study</td><td>University acceptance, funds proof</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family of resident</td><td>Relationship proof, accommodation, income</td><td>2 years, renewable</td></tr><tr><td>Permanent Residence (Investor)</td><td>Property purchase</td><td>€300,000+ property investment</td><td>Permanent</td></tr><tr><td>Temporary Residence</td><td>Self-funded individuals</td><td>Sufficient income, health insurance, accommodation</td><td>2 years, renewable</td></tr></tbody></table><h3 id="digital-nomad-visa" tabindex="-1">Digital Nomad Visa <a class="header-anchor" href="#digital-nomad-visa" aria-label="Permalink to &quot;Digital Nomad Visa&quot;">​</a></h3><p>Cyprus launched a <strong>Digital Nomad Visa</strong> in 2022:</p><ul><li>Valid for up to <strong>12 months</strong>, renewable for another <strong>2 years</strong> (total 3 years)</li><li>Must work remotely for a company outside Cyprus</li><li><strong>Income requirement</strong>: €3,500+/month (net)</li><li>No tax liability in Cyprus for the first 5 years (if non-domiciled)</li><li>Cannot work for Cypriot employers or clients</li><li>Family members can accompany</li><li>Application through the Civil Registry and Migration Department</li><li>Quota of 500 visas initially (may be expanded)</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for at least 6 months</li><li>[ ] <strong>Visa/Residence</strong>: Check requirements for your nationality</li><li>[ ] <strong>Health Insurance</strong>: EU citizens: EHIC; others: private insurance mandatory</li><li>[ ] <strong>HRT</strong>: Get 3-6 month supply and doctor&#39;s letter (English or Greek)</li><li>[ ] <strong>Medical Records</strong>: Translated into Greek if needed</li><li>[ ] <strong>Banking</strong>: International banking options</li><li>[ ] <strong>Housing</strong>: Research rental market (bazaraki.com, cyprusproperty.net)</li><li>[ ] <strong>Language</strong>: English widely spoken; basic Greek helpful</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] <strong>Register with Migration Department</strong> for Yellow Slip (EU) or residence permit</li><li>[ ] <strong>Get ARC</strong> (Alien Registration Certificate) — non-EU citizens</li><li>[ ] <strong>Register with GESY</strong> (General Healthcare System)</li><li>[ ] <strong>Open bank account</strong> — Bank of Cyprus, Hellenic Bank, Alpha Bank</li><li>[ ] <strong>Get Cypriot phone number</strong> — Cyta, Epic, PrimeTel</li><li>[ ] <strong>Connect with Accept Cyprus</strong> for LGBTQ+ community</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Nicosia</th><th>Limassol</th><th>Larnaca/Paphos</th></tr></thead><tbody><tr><td>Rent (1-bedroom)</td><td>€600-900/month</td><td>€800-1,300/month</td><td>€500-750/month</td></tr><tr><td>Groceries</td><td>€250-400/month</td><td>€300-450/month</td><td>€220-380/month</td></tr><tr><td>Utilities</td><td>€100-200/month</td><td>€100-200/month</td><td>€100-180/month</td></tr><tr><td>Internet</td><td>€30-50/month</td><td>€30-50/month</td><td>€30-50/month</td></tr><tr><td>Eating out</td><td>€12-25/meal</td><td>€15-30/meal</td><td>€10-20/meal</td></tr></tbody></table><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li><strong>Official languages</strong>: Greek and Turkish</li><li><strong>English</strong>: Very widely spoken — Cyprus is one of the most English-friendly EU countries</li><li>English is used in government, business, and daily life</li><li>Many Cypriots speak English as a first or second language</li><li>Greek is useful for integration but not essential for daily life</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Mediterranean climate</strong>: Hot summers, mild winters</li><li><strong>Summer</strong>: 25°C to 40°C (June-September)</li><li><strong>Winter</strong>: 10°C to 20°C (December-February)</li><li><strong>Sunshine</strong>: Over 300 sunny days per year</li><li><strong>Best time to arrive</strong>: Spring or autumn</li></ul><h3 id="trans-specific-considerations" tabindex="-1">Trans-Specific Considerations <a class="header-anchor" href="#trans-specific-considerations" aria-label="Permalink to &quot;Trans-Specific Considerations&quot;">​</a></h3><ul><li><strong>Cyprus is socially conservative</strong> — public displays of affection should be cautious</li><li><strong>Nicosia and Limassol</strong> are the most tolerant areas</li><li>Rural areas and smaller towns are more traditional</li><li><strong>Accept Cyprus</strong> is the main LGBTQ+ organization providing support</li><li>Limited trans healthcare — plan for accessing care abroad (Greece, UK)</li><li>GESY system covers basic healthcare but not specialized trans care</li><li>Legal gender recognition requires navigating the medicalized court system</li><li>Growing expat community provides social support</li></ul><h3 id="important-note-on-northern-cyprus" tabindex="-1">Important Note on Northern Cyprus <a class="header-anchor" href="#important-note-on-northern-cyprus" aria-label="Permalink to &quot;Important Note on Northern Cyprus&quot;">​</a></h3><ul><li>The northern part of Cyprus is a <strong>separate political entity</strong> only recognized by Turkey</li><li>Legal protections for trans people do not apply in the north</li><li>Immigration to the north follows separate rules</li><li>Most trans-friendly resources and protections exist in the Republic of Cyprus (south)</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.moi.gov.cy/" target="_blank" rel="noreferrer">Civil Registry and Migration Department</a></li><li><a href="https://www.gesy.org.cy/" target="_blank" rel="noreferrer">GESY - General Healthcare System</a></li><li><a href="https://www.bazaraki.com/" target="_blank" rel="noreferrer">Bazaraki - Housing</a></li><li><a href="https://www.accept.cy/" target="_blank" rel="noreferrer">Accept Cyprus - LGBTQ+ Association</a></li><li><a href="https://www.moi.gov.cy/" target="_blank" rel="noreferrer">Digital Nomad Visa Information</a></li></ul>',28))])}const v=o(h,[["render",c]]);export{b as __pageData,v as default};
